        if(isValidUsernameAndPasswordCombination(username, password)) {   // This is just an example of how you could do this validation in a real-world scenario - the actual implementation would be much more complex and error prone.  The method 'authenticate' should not return true or false but rather throw exceptions when something goes wrong
            setAuthenticatedUser(username);   // This is just an example of how you could do this in a real-world scenario - the actual implementation would be much more complex and error prone.  The method 'authenticate' should not return true or false but rather throw exceptions when something goes wrong
            return true;    // Returning True indicates success, so if everything went fine then we can conclude that this is a valid login attempt with the provided credentials  
        } else {     // Else there was an issue - no user could be logged in. We should log it and throw appropriate exceptions or error codes etc..  For example: 'throw new AuthenticationFailedException("Invalid username/password combination");' which can then likely result from a Spring Security ExceptionsHandler
            return false;   // Returning False indicates failure, so if something went wrong we will get an exception to handle it in our code. So here is the point where you could decide what kind of exceptions should be thrown and how they ought to look like (depends on context)  For example: 'throw new UsernameNotFoundException("Invalid username");' which can then likely result from a Spring Security AuthenticationProvider
        }   // end else statement    
